hooks.command:
python -c "
import json,sys,re
d=json.load(sys.stdin)
p=(d.get('tool_input',{}).get('file_path','') or '').replace('\\\\','/')
if not p.endswith('.tsx'): sys.exit(0)
if '/src/app/api/' in p: sys.exit(0)
try:
    content=open(p,encoding='utf-8',errors='replace').read()
except: sys.exit(0)
hooks=re.compile(r'\\b(useState|useEffect|useRef|useCallback|useMemo|useContext|useReducer)\\s*[(<]')
has_directive=re.compile(r'''['\"]use client['\"]''',re.MULTILINE)
if hooks.search(content) and not has_directive.search(content):
    print('\u2192 AVISO: Este componente usa hooks React sin \"use client\" — fallará el build de Vercel si lo importa un Server Component.',file=sys.stderr)
"
